package membership

import (
	"math/rand"
	"sync"
	"time"
)

// SWIMConfig holds parameters for the SWIM failure detector.
type SWIMConfig struct {
	// ProbeInterval is how often to probe a random member.
	ProbeInterval time.Duration
	// ProbeTimeout is how long to wait for a direct ack.
	ProbeTimeout time.Duration
	// IndirectChecks is the number of indirect probes to send.
	IndirectChecks int
	// SuspicionTimeout is how long a member stays suspect before being declared dead.
	SuspicionTimeout time.Duration
}

const maxProbeHistoryEvents = 1024

// DefaultSWIMConfig returns reasonable defaults.
func DefaultSWIMConfig() SWIMConfig {
	return SWIMConfig{
		ProbeInterval:    time.Second,
		ProbeTimeout:     500 * time.Millisecond,
		IndirectChecks:   3,
		SuspicionTimeout: 5 * time.Second,
	}
}

// ProbeResult represents the outcome of a ping probe.
type ProbeResult int

const (
	ProbeAck     ProbeResult = iota // Direct ack received
	ProbeNack                       // No response
	ProbeTimeout                    // Timed out
)

// ProbeFunc is a callback that simulates or performs a ping probe to a target.
// Returns ProbeAck if the target responds, ProbeNack/ProbeTimeout otherwise.
type ProbeFunc func(target string) ProbeResult

// IndirectProbeFunc asks a mediator to probe the target on our behalf.
type IndirectProbeFunc func(mediator, target string) ProbeResult

// SWIMDetector implements the SWIM protocol for failure detection.
// It runs probe rounds, manages suspicion timers, and updates the member list.
type SWIMDetector struct {
	mu            sync.Mutex
	config        SWIMConfig
	memberList    *MemberList
	suspicionMap  map[string]time.Time // nodeID → when suspicion started
	probeFunc     ProbeFunc
	indirectFunc  IndirectProbeFunc
	rng           *rand.Rand
	roundCount    uint64
	probeHistory  []ProbeEvent
}

// ProbeEvent records the outcome of a single probe.
type ProbeEvent struct {
	Round     uint64
	Target    string
	Result    ProbeResult
	Indirect  bool
	Timestamp time.Time
}

// NewSWIMDetector creates a failure detector for the given membership list.
func NewSWIMDetector(ml *MemberList, config SWIMConfig, probeFn ProbeFunc, indirectFn IndirectProbeFunc, seed int64) *SWIMDetector {
	return &SWIMDetector{
		config:       config,
		memberList:   ml,
		suspicionMap: make(map[string]time.Time),
		probeFunc:    probeFn,
		indirectFunc: indirectFn,
		rng:          rand.New(rand.NewSource(seed)),
	}
}

// RunProbeRound executes one round of the SWIM protocol:
// 1. Select a random alive member to probe
// 2. Send a direct ping
// 3. If no ack, send indirect pings through k mediators
// 4. If still no ack, mark as suspect
// 5. Check suspicion timeouts and declare dead members
func (sd *SWIMDetector) RunProbeRound() *ProbeEvent {
	sd.mu.Lock()
	defer sd.mu.Unlock()
	sd.roundCount++

	// Step 1: Select target
	alive := sd.memberList.AliveMembers(true)
	if len(alive) == 0 {
		return nil
	}
	targetIdx := sd.rng.Intn(len(alive))
	target := alive[targetIdx]

	// Step 2: Direct probe
	result := sd.probeFunc(target)
	event := &ProbeEvent{
		Round:     sd.roundCount,
		Target:    target,
		Result:    result,
		Indirect:  false,
		Timestamp: time.Now(),
	}
	sd.recordProbeEvent(*event)

	if result == ProbeAck {
		delete(sd.suspicionMap, target)
		return event
	}

	// Step 3: Indirect probes
	mediators := sd.selectMediators(alive, target, sd.config.IndirectChecks)
	indirectAck := false
	for _, med := range mediators {
		ir := sd.indirectFunc(med, target)
		sd.recordProbeEvent(ProbeEvent{
			Round:     sd.roundCount,
			Target:    target,
			Result:    ir,
			Indirect:  true,
			Timestamp: time.Now(),
		})
		if ir == ProbeAck {
			indirectAck = true
			break
		}
	}

	if indirectAck {
		delete(sd.suspicionMap, target)
		event.Result = ProbeAck
		return event
	}

	// Step 4: Mark as suspect
	if _, isSuspect := sd.suspicionMap[target]; !isSuspect {
		m := sd.memberList.Get(target)
		if m != nil {
			sd.memberList.Suspect(target, m.Incarnation)
			sd.suspicionMap[target] = time.Now()
		}
	}

	// Step 5: Check suspicion timeouts
	sd.checkSuspicionTimeouts()

	return event
}

func (sd *SWIMDetector) recordProbeEvent(event ProbeEvent) {
	if len(sd.probeHistory) < maxProbeHistoryEvents {
		sd.probeHistory = append(sd.probeHistory, event)
		return
	}
	copy(sd.probeHistory, sd.probeHistory[1:])
	sd.probeHistory[len(sd.probeHistory)-1] = event
}

// checkSuspicionTimeouts promotes suspects to dead if their timeout has expired.
func (sd *SWIMDetector) checkSuspicionTimeouts() {
	now := time.Now()
	for nodeID, started := range sd.suspicionMap {
		if now.Sub(started) >= sd.config.SuspicionTimeout {
			m := sd.memberList.Get(nodeID)
			if m != nil {
				sd.memberList.Dead(nodeID, m.Incarnation)
			}
			delete(sd.suspicionMap, nodeID)
		}
	}
}

// selectMediators picks up to n random alive members excluding target and self.
func (sd *SWIMDetector) selectMediators(alive []string, target string, n int) []string {
	candidates := make([]string, 0, len(alive))
	for _, id := range alive {
		if id != target {
			candidates = append(candidates, id)
		}
	}
	if n > len(candidates) {
		n = len(candidates)
	}
	for i := len(candidates) - 1; i > 0; i-- {
		j := sd.rng.Intn(i + 1)
		candidates[i], candidates[j] = candidates[j], candidates[i]
	}
	return candidates[:n]
}

// History returns the probe history.
func (sd *SWIMDetector) History() []ProbeEvent {
	sd.mu.Lock()
	defer sd.mu.Unlock()
	result := make([]ProbeEvent, len(sd.probeHistory))
	copy(result, sd.probeHistory)
	return result
}

// Rounds returns the number of probe rounds executed.
func (sd *SWIMDetector) Rounds() uint64 {
	sd.mu.Lock()
	defer sd.mu.Unlock()
	return sd.roundCount
}

// SuspectCount returns the number of currently suspected members.
func (sd *SWIMDetector) SuspectCount() int {
	sd.mu.Lock()
	defer sd.mu.Unlock()
	return len(sd.suspicionMap)
}
package sim

import (
	"math/rand"
	"sort"
	"sync"

	"github.com/Mustafa4ngin/SwarmSync/pkg/gossip"
	"github.com/Mustafa4ngin/SwarmSync/pkg/merkle"
)

// Event represents a discrete simulation event.
type Event struct {
	Time     uint64
	Type     EventType
	Source   string
	Target   string
	Payload  interface{}
}

// EventType identifies the kind of simulation event.
type EventType int

const (
	EventGossip     EventType = iota
	EventMerkleDiff
	EventNodeJoin
	EventNodeLeave
	EventPartition
	EventHeal
)

const maxEventLogEntries = 4096

// NetworkSim simulates a cluster of gossip nodes with configurable
// network conditions: latency, packet loss, and partitions.
type NetworkSim struct {
	mu         sync.Mutex
	nodes      map[string]*gossip.Protocol
	stores     map[string]*gossip.StateStore
	partitions map[string]map[string]bool // blocked connections
	clock      uint64
	events     []Event
	dropRate   float64 // probability of dropping a message
	rng        *rand.Rand
}

// NewNetworkSim creates a simulation.
func NewNetworkSim(seed int64) *NetworkSim {
	return &NetworkSim{
		nodes:      make(map[string]*gossip.Protocol),
		stores:     make(map[string]*gossip.StateStore),
		partitions: make(map[string]map[string]bool),
		rng:        rand.New(rand.NewSource(seed)),
	}
}

// AddNode registers a node in the simulation.
func (ns *NetworkSim) AddNode(nodeID string, fanout int) {
	ns.mu.Lock()
	defer ns.mu.Unlock()
	store := gossip.NewStateStore(nodeID)
	sel := gossip.NewRandomPeerSelector(ns.rng.Int63())
	proto := gossip.NewProtocol(nodeID, store, sel, fanout)
	ns.nodes[nodeID] = proto
	ns.stores[nodeID] = store
	ns.recordEvent(Event{
		Time:   ns.clock,
		Type:   EventNodeJoin,
		Source: nodeID,
	})
}

// RemoveNode removes a node from the simulation.
func (ns *NetworkSim) RemoveNode(nodeID string) {
	ns.mu.Lock()
	defer ns.mu.Unlock()
	delete(ns.nodes, nodeID)
	delete(ns.stores, nodeID)
	delete(ns.partitions, nodeID)
	for _, blocked := range ns.partitions {
		delete(blocked, nodeID)
	}
	ns.recordEvent(Event{
		Time:   ns.clock,
		Type:   EventNodeLeave,
		Source: nodeID,
	})
}

// SetDropRate sets the probability of dropping a gossip message.
func (ns *NetworkSim) SetDropRate(rate float64) {
	ns.mu.Lock()
	defer ns.mu.Unlock()
	ns.dropRate = rate
}

// Partition blocks communication between two nodes.
func (ns *NetworkSim) Partition(a, b string) {
	ns.mu.Lock()
	defer ns.mu.Unlock()
	if ns.partitions[a] == nil {
		ns.partitions[a] = make(map[string]bool)
	}
	if ns.partitions[b] == nil {
		ns.partitions[b] = make(map[string]bool)
	}
	ns.partitions[a][b] = true
	ns.partitions[b][a] = true
	ns.recordEvent(Event{
		Time:   ns.clock,
		Type:   EventPartition,
		Source: a,
		Target: b,
	})
}

// Heal restores communication between two nodes.
func (ns *NetworkSim) Heal(a, b string) {
	ns.mu.Lock()
	defer ns.mu.Unlock()
	if ns.partitions[a] != nil {
		delete(ns.partitions[a], b)
	}
	if ns.partitions[b] != nil {
		delete(ns.partitions[b], a)
	}
	ns.recordEvent(Event{
		Time:   ns.clock,
		Type:   EventHeal,
		Source: a,
		Target: b,
	})
}

// isPartitioned checks if two nodes are partitioned.
func (ns *NetworkSim) isPartitioned(a, b string) bool {
	if blocked, ok := ns.partitions[a]; ok {
		return blocked[b]
	}
	return false
}

// RunGossipRound executes one round of gossip for all nodes.
// Each node picks fanout peers and performs push-pull, subject to
// network conditions (partitions, packet loss).
func (ns *NetworkSim) RunGossipRound() SimRoundResult {
	ns.mu.Lock()
	defer ns.mu.Unlock()
	ns.clock++

	var result SimRoundResult
	peerList := ns.peerList()

	for nodeID, proto := range ns.nodes {
		sel := gossip.NewRandomPeerSelector(ns.rng.Int63())
		peers := sel.SelectPeers(peerList, nodeID, proto.Fanout())

		for _, peerID := range peers {
			if ns.isPartitioned(nodeID, peerID) {
				result.Blocked++
				continue
			}
			if ns.dropRate > 0 && ns.rng.Float64() < ns.dropRate {
				result.Dropped++
				continue
			}
			peerStore, ok := ns.stores[peerID]
			if !ok {
				continue
			}
			exchange := proto.PushPull(peerStore)
			result.Exchanges++
			result.PushedTotal += exchange.PushedTo
			result.PulledTotal += exchange.PulledFrom

			ns.recordEvent(Event{
				Time:    ns.clock,
				Type:    EventGossip,
				Source:  nodeID,
				Target:  peerID,
				Payload: exchange,
			})
		}
	}
	return result
}

// RunMerkleSyncRound performs merkle-based anti-entropy between random pairs.
func (ns *NetworkSim) RunMerkleSyncRound() int {
	ns.mu.Lock()
	defer ns.mu.Unlock()
	ns.clock++

	synced := 0
	peerList := ns.peerList()
	if len(peerList) < 2 {
		return 0
	}

	for nodeID, store := range ns.stores {
		// Pick a random peer
		sel := gossip.NewRandomPeerSelector(ns.rng.Int63())
		peers := sel.SelectPeers(peerList, nodeID, 1)
		if len(peers) == 0 {
			continue
		}
		peerID := peers[0]
		if ns.isPartitioned(nodeID, peerID) {
			continue
		}

		peerStore, ok := ns.stores[peerID]
		if !ok {
			continue
		}

		// Build merkle trees from both stores
		localTree := storeToTree(store)
		remoteTree := storeToTree(peerStore)
		diff := merkle.FastDiff(localTree, remoteTree)

		// Sync differing keys using Apply to preserve versions
		for _, key := range diff.OnlyRemote {
			e, ok := peerStore.GetEntry(key)
			if ok {
				store.Apply([]*gossip.StateEntry{e})
				synced++
			}
		}
		for _, key := range diff.OnlyLocal {
			e, ok := store.GetEntry(key)
			if ok {
				peerStore.Apply([]*gossip.StateEntry{e})
				synced++
			}
		}
		for _, key := range diff.Different {
			le, _ := store.GetEntry(key)
			re, _ := peerStore.GetEntry(key)
			if le != nil && re != nil {
				if le.Version > re.Version {
					peerStore.Apply([]*gossip.StateEntry{le})
				} else {
					store.Apply([]*gossip.StateEntry{re})
				}
				synced++
			}
		}

		ns.recordEvent(Event{
			Time:    ns.clock,
			Type:    EventMerkleDiff,
			Source:  nodeID,
			Target:  peerID,
			Payload: diff.TotalDiffs(),
		})
	}
	return synced
}

func (ns *NetworkSim) recordEvent(event Event) {
	if len(ns.events) < maxEventLogEntries {
		ns.events = append(ns.events, event)
		return
	}
	copy(ns.events, ns.events[1:])
	ns.events[len(ns.events)-1] = event
}

